using System.Web;

namespace SmartHealthReport.Templates.Helpers;

public static class HtmlHelpers
{
    public static string Encode(string text) => HttpUtility.HtmlEncode(text);

    public static string JsEscape(string text) =>
        text.Replace("\\", "\\\\").Replace("\"", "\\\"").Replace("\n", "\\n").Replace("\r", "");

    public static string StatusTrend(string status) => status switch
    {
        "Normal" => "up",
        "Abnormal" => "down",
        _ => "same"
    };

    private static readonly System.Collections.Concurrent.ConcurrentDictionary<string, string> _svgBase64Cache = new();

    public static string SvgIcon(string fileName, int size = 40)
    {
        var base64 = _svgBase64Cache.GetOrAdd(fileName, key =>
            Convert.ToBase64String(System.Text.Encoding.UTF8.GetBytes(AssetLoader.Load(key))));
        return $"""<img src="data:image/svg+xml;base64,{base64}" width="{size}" height="{size}" alt="" />""";
    }

    public static string DropletIcon(int size = 22) =>
        $"""<svg width="{size}" height="{size}" viewBox="0 0 24 24" fill="#333" style="vertical-align:middle"><path d="M12 2C12 2 5 11 5 15.5C5 19.09 8.13 22 12 22C15.87 22 19 19.09 19 15.5C19 11 12 2 12 2Z"/></svg>""";

