        "down" => """<span class="trend-down"><svg width="15" height="15" viewBox="0 0 195 248" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M103.234 245.01C100.087 248.28 94.8515 248.28 91.7043 245.01L2.25122 152.047C-2.63916 146.964 0.96265 138.5 8.01587 138.5L47.469 138.5L47.469 17C47.4691 7.61117 55.0802 -4.57764e-05 64.469 -4.57764e-05L130.469 -4.57764e-05C139.858 5.40813e-05 147.469 7.61123 147.469 17L147.469 138.5H186.922C193.975 138.5 197.577 146.964 192.687 152.047L103.234 245.01Z" fill="#8E0000"/></svg></span>""",
        _ => """<span class="trend-same">&#x25CF;</span>"""
