    public static string RowClass(string trend) => trend switch
    {
        "up" => "row-normal",
        "down" => "row-abnormal",
        _ => "row-borderline"
    };

    public static string StatusBadgeClass(string status) => status switch
    {
        "Normal" => "badge-normal",
        "Abnormal" => "badge-abnormal",
        _ => "badge-borderline"
    };

    public static string StatusLabel(string status) => status switch
    {
        "Normal" => "Normal",
        "Abnormal" => "Abnormal",
        _ => "Borderline"
    };

    public static string CardClass(string status) => status switch
    {
        "Normal" => "normal",
        "Abnormal" => "abnormal",
        _ => "borderline"
    };

    public static string TrendSymbol(string trend) => trend switch
    {
        "up" => """<svg width="10" height="13" viewBox="0 0 195 248" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M91.7041 2.45281C94.8512 -0.817663 100.086 -0.817541 103.233 2.45281L192.687 95.4157C197.577 100.498 193.975 108.963 186.922 108.963H147.469V230.463C147.469 239.851 139.858 247.463 130.469 247.463H64.4688C55.0801 247.462 47.4688 239.851 47.4688 230.463V108.963H8.01565C0.962755 108.962 -2.63902 100.498 2.251 95.4157L91.7041 2.45281Z" fill="white"/></svg>""",
        "down" => """<svg width="10" height="13" viewBox="0 0 195 248" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M103.234 245.01C100.087 248.28 94.8515 248.28 91.7043 245.01L2.25122 152.047C-2.63916 146.964 0.96265 138.5 8.01587 138.5L47.469 138.5L47.469 17C47.4691 7.61117 55.0802 -4.57764e-05 64.469 -4.57764e-05L130.469 -4.57764e-05C139.858 5.40813e-05 147.469 7.61123 147.469 17L147.469 138.5H186.922C193.975 138.5 197.577 146.964 192.687 152.047L103.234 245.01Z" fill="white"/></svg>""",
